package com.example.bankingapp.data;

import android.os.Handler;
import android.os.Looper;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.Executor;
import java.util.concurrent.Executors;

public class BankRepository {

    private static BankRepository instance;
    private final Executor executor = Executors.newSingleThreadExecutor();
    private final Handler mainThreadHandler = new Handler(Looper.getMainLooper());

    private final Account userAccount;
    private final List<Transaction> transactionHistory;

    private BankRepository() {
        // Initialize with a dummy account and some initial balance
        userAccount = new Account("ACC001", new BigDecimal("1000.00"));
        transactionHistory = Collections.synchronizedList(new ArrayList<>());
        // Add some initial transactions
        transactionHistory.add(new Transaction("ACC001", Transaction.TransactionType.DEPOSIT, new BigDecimal("1000.00")));
    }

    public static synchronized BankRepository getInstance() {
        if (instance == null) {
            instance = new BankRepository();
        }
        return instance;
    }

    public interface BankOperationCallback<T> {
        void onSuccess(T result);
        void onError(String errorMessage);
    }

    public void getAccountBalance(final String accountId, final BankOperationCallback<BigDecimal> callback) {
        executor.execute(() -> {
            // Simulate network delay
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                mainThreadHandler.post(() -> callback.onError("Operation interrupted"));
                return;
            }

            if (userAccount.getAccountId().equals(accountId)) {
                mainThreadHandler.post(() -> callback.onSuccess(userAccount.getBalance()));
            } else {
                mainThreadHandler.post(() -> callback.onError("Account not found"));
            }
        });
    }

    public void getTransactionHistory(final String accountId, final BankOperationCallback<List<Transaction>> callback) {
        executor.execute(() -> {
            // Simulate network delay
            try {
                Thread.sleep(1500);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                mainThreadHandler.post(() -> callback.onError("Operation interrupted"));
                return;
            }

            // Return a copy to prevent external modification and in reverse order (newest first)
            List<Transaction> filteredTransactions = new ArrayList<>();
            for (Transaction t : transactionHistory) {
                if (t.getAccountId().equals(accountId)) {
                    filteredTransactions.add(t);
                }
            }
            Collections.reverse(filteredTransactions); // Newest first
            mainThreadHandler.post(() -> callback.onSuccess(Collections.unmodifiableList(filteredTransactions)));
        });
    }

    public void performTransaction(final String accountId, final Transaction.TransactionType type,
                                   final BigDecimal amount, final BankOperationCallback<Transaction> callback) {
        executor.execute(() -> {
            // Simulate network delay
            try {
                Thread.sleep(2000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                mainThreadHandler.post(() -> callback.onError("Operation interrupted"));
                return;
            }

            if (!userAccount.getAccountId().equals(accountId)) {
                mainThreadHandler.post(() -> callback.onError("Account not found"));
                return;
            }

            BigDecimal newBalance = userAccount.getBalance();
            Transaction newTransaction = null;

            // Simple security: basic validation
            if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
                mainThreadHandler.post(() -> callback.onError("Invalid amount. Must be positive."));
                return;
            }

            switch (type) {
                case DEPOSIT:
                    newBalance = newBalance.add(amount);
                    newTransaction = new Transaction(accountId, type, amount);
                    break;
                case WITHDRAWAL:
                    if (newBalance.compareTo(amount) >= 0) {
                        newBalance = newBalance.subtract(amount);
                        newTransaction = new Transaction(accountId, type, amount);
                    } else {
                        mainThreadHandler.post(() -> callback.onError("Insufficient funds"));
                        return;
                    }
                    break;
            }

            if (newTransaction != null) {
                userAccount.setBalance(newBalance);
                transactionHistory.add(newTransaction);
                mainThreadHandler.post(() -> callback.onSuccess(newTransaction));
            } else {
                mainThreadHandler.post(() -> callback.onError("Transaction failed unexpectedly"));
            }
        });
    }
}

// File: app/src/main/java/com/example/bankingapp/ui/BankingViewModel.java
package com.example.bankingapp.ui;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.bankingapp.data.BankRepository;
import com.example.bankingapp.data.Transaction;

import java.math.BigDecimal;
import java.util.List;

public class BankingViewModel extends ViewModel {

    private final BankRepository bankRepository;
    private final String currentAccountId = "ACC001"; // Hardcoded for simplicity

    private final MutableLiveData<BigDecimal> _accountBalance = new MutableLiveData<>();
    public LiveData<BigDecimal> getAccountBalance() {
        return _accountBalance;
    }

    private final MutableLiveData<List<Transaction>> _transactionHistory = new MutableLiveData<>();
    public LiveData<List<Transaction>> getTransactionHistory() {
        return _transactionHistory;
    }

    private final MutableLiveData<String> _errorMessage = new MutableLiveData<>();
    public LiveData<String> getErrorMessage() {
        return _errorMessage;
    }

    private final MutableLiveData<Boolean> _isLoading = new MutableLiveData<>();
    public LiveData<Boolean> getIsLoading() {
        return _isLoading;
    }

    public BankingViewModel() {
        bankRepository = BankRepository.getInstance();
        loadAccountData();
    }

    public void loadAccountData() {
        _isLoading.postValue(true);
        bankRepository.getAccountBalance(currentAccountId, new BankRepository.BankOperationCallback<BigDecimal>() {
            @Override
            public void onSuccess(BigDecimal result) {
                _accountBalance.postValue(result);
                loadTransactionHistoryInternal();
            }

            @Override
            public void onError(String errorMessage) {
                _errorMessage.postValue(errorMessage);
                _isLoading.postValue(false);
            }
        });
    }

    private void loadTransactionHistoryInternal() {
        bankRepository.getTransactionHistory(currentAccountId, new BankRepository.BankOperationCallback<List<Transaction>>() {
            @Override
            public void onSuccess(List<Transaction> result) {
                _transactionHistory.postValue(result);
                _isLoading.postValue(false);
            }

            @Override
            public void onError(String errorMessage) {
                _errorMessage.postValue(errorMessage);
                _isLoading.postValue(false);
            }
        });
    }

    public void processDeposit(String amountString) {
        processTransaction(amountString, Transaction.TransactionType.DEPOSIT);
    }

    public void processWithdrawal(String amountString) {
        processTransaction(amountString, Transaction.TransactionType.WITHDRAWAL);
    }

    private void processTransaction(String amountString, Transaction.TransactionType type) {
        try {
            BigDecimal amount = new BigDecimal(amountString);

            _isLoading.postValue(true);
            bankRepository.performTransaction(currentAccountId, type, amount, new BankRepository.BankOperationCallback<Transaction>() {
                @Override
                public void onSuccess(Transaction result) {
                    loadAccountData(); // Reload balance and history
                    _errorMessage.postValue(type.name() + " successful!"); // Simple success message
                }

                @Override
                public void onError(String errorMessage) {
                    _errorMessage.postValue(errorMessage);
                    _isLoading.postValue(false);
                }
            });

        } catch (NumberFormatException e) {
            _errorMessage.postValue("Invalid amount format.");
        } catch (Exception e) {
            _errorMessage.postValue("An unexpected error occurred: " + e.getMessage());
        }
    }
}

// File: app/src/main/java/com/example/bankingapp/ui/TransactionAdapter.java
package com.example.bankingapp.ui;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.bankingapp.R;
import com.example.bankingapp.data.Transaction;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class TransactionAdapter extends RecyclerView.Adapter<TransactionAdapter.TransactionViewHolder> {

    private List<Transaction> transactions = new ArrayList<>();
    private final SimpleDateFormat dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.getDefault());

    public void setTransactions(List<Transaction> newTransactions) {
        this.transactions = newTransactions;
        notifyDataSetChanged();
    }

    @NonNull
    @Override
    public TransactionViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_transaction, parent, false);
        return new TransactionViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull TransactionViewHolder holder, int position) {
        Transaction transaction = transactions.get(position);
        holder.bind(transaction);
    }

    @Override
    public int getItemCount() {
        return transactions.size();
    }

    class TransactionViewHolder extends RecyclerView.ViewHolder {
        private final TextView transactionDetails;
        private final TextView transactionTimestamp;

        public TransactionViewHolder(@NonNull View itemView) {
            super(itemView);
            transactionDetails = itemView.findViewById(R.id.textView_transaction_details);
            transactionTimestamp = itemView.findViewById(R.id.textView_transaction_timestamp);
        }

        public void bind(Transaction transaction) {
            String details = itemView.getContext().getString(R.string.transaction_item_format,
                    transaction.getType().name(),
                    transaction.getAmount(),
                    transaction.getTransactionId().substring(0, 8) // Show first 8 chars of UUID
            );
            transactionDetails.setText(details);
            transactionTimestamp.setText(dateFormat.format(transaction.getTimestamp()));
        }
    }
}

// File: app/src/main/java/com/example/bankingapp/ui/BankingActivity.java
package com.example.bankingapp.ui;

import android.os.Bundle;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.bankingapp.R;

import java.util.Locale;

public class BankingActivity extends AppCompatActivity {

    private BankingViewModel bankingViewModel;
    private TextView balanceTextView;
    private EditText amountEditText;
    private Button depositButton;
    private Button withdrawButton;
    private RecyclerView transactionsRecyclerView;
    private TransactionAdapter transactionAdapter;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        balanceTextView = findViewById(R.id.textView_balance);
        amountEditText = findViewById(R.id.editText_amount);
        depositButton = findViewById(R.id.button_deposit);
        withdrawButton = findViewById(R.id.button_withdraw);
        transactionsRecyclerView = findViewById(R.id.recyclerView_transactions);

        transactionAdapter = new TransactionAdapter();
        transactionsRecyclerView.setLayoutManager(new LinearLayoutManager(this));
        transactionsRecyclerView.setAdapter(transactionAdapter);

        bankingViewModel = new ViewModelProvider(this).get(BankingViewModel.class);

        observeViewModel();
        setupListeners();
    }

    private void observeViewModel() {
        bankingViewModel.getAccountBalance().observe(this, balance -> {
            balanceTextView.setText(String.format(Locale.getDefault(), getString(R.string.account_balance), balance));
        });

        bankingViewModel.getTransactionHistory().observe(this, transactions -> {
            transactionAdapter.setTransactions(transactions);
        });

        bankingViewModel.getErrorMessage().observe(this, message -> {
            if (message != null && !message.isEmpty()) {
                Toast.makeText(BankingActivity.this, message, Toast.LENGTH_SHORT).show();
                bankingViewModel.getErrorMessage().setValue(null); // Consume the message
            }
        });

        bankingViewModel.getIsLoading().observe(this, isLoading -> {
            // No explicit progress indicator, Toast serves as simple feedback
            setUIEnabled(!isLoading);
        });
    }

    private void setupListeners() {
        depositButton.setOnClickListener(v -> {
            String amount = amountEditText.getText().toString();
            bankingViewModel.processDeposit(amount);
            amountEditText.setText(""); // Clear input
        });

        withdrawButton.setOnClickListener(v -> {
            String amount = amountEditText.getText().toString();
            bankingViewModel.processWithdrawal(amount);
            amountEditText.setText(""); // Clear input
        });
    }

    private void setUIEnabled(boolean enabled) {
        amountEditText.setEnabled(enabled);
        depositButton.setEnabled(enabled);
        withdrawButton.setEnabled(enabled);
        // RecyclerView interaction is typically independent of this, but keeping it consistent
        transactionsRecyclerView.setClickable(enabled);
    }
}